//C. Make Them Equal #include<bits/stdc++.h>using namespace std;#define int long long int void fast_io() {    std::ios_base::sync_with_stdio(false);    std::cin.tie(NULL);    std::cout.tie(NULL);} signed main(){    fast_io();    int t;    cin>>t;    while(t--){        int n;        cin>>n;        char c;        cin>>c;        string s;        cin>>s;        int a=0;        for(int i=0;i<n;i++){            if(s[i]!=c){                a++;            }        }        if(a==0){            cout<<0<<endl;            continue;        }        int me=0;        for(int i=2;i<=n;i++){            int b=0;            for(int j=i;j<=n;j=j+i){                if(s[j-1]!=c){                    b=1;                    break;                }            }            if(b==0){                me=i;                break;            }        }        if(me!=0){            cout<<1<<endl;            cout<<me<<endl;            continue;        }        cout<<2<<endl;        cout<<n-1<<" "<<n<<endl;            }}